INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('pukao-6f0ba476-moex-00039', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-114-a7c7609b', 'sub-pukao-6f0ba476-02', NULL, 'single_choice', '甲出租自有A地於乙興建B屋，房屋完工後乙請求甲為地上權登記，並登記在案。嗣後甲將A地 出賣並辦理移轉所有權登記於丙。下列敘述，何者正確？', '["應於期限內完成地上權登記，逾期未登記者，不得請求登記", "於丙受讓取得A地時，乙所有之B屋仍合法存於A地上，稱「法定地上權」", "丙基於A地所有人地位，得請求乙拆除B屋返還A地", "A地出賣時，乙有依同樣條件優先購買之權"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:43+00:00", "source_pdf_sha1": "b84e55ea72f9", "answer_pdf_sha1": "bebb5c6f63b3", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "413", "s": "0906", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00040', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-114-a7c7609b', 'sub-pukao-6f0ba476-02', NULL, 'single_choice', '契約當事人約定其契約須用一定方式者，如該方式為契約成立之要件，則在該方式未完成前，該 契約之效力如何？', '["推定成立", "推定不成立", "視為成立", "視為不成立"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:43+00:00", "source_pdf_sha1": "b84e55ea72f9", "answer_pdf_sha1": "bebb5c6f63b3", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "413", "s": "0906", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00041', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-114-a7c7609b', 'sub-pukao-6f0ba476-02', NULL, 'single_choice', '甲有一愛犬A，某日A走失，被乙拾獲並飼養於家中。下列敘述，何者錯誤？', '["A為遺失物", "乙為善意占有人", "甲得於二年內向乙請求回復其物", "甲向乙請求回復其物後，乙仍取得拾獲期間A之所有權"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:43+00:00", "source_pdf_sha1": "b84e55ea72f9", "answer_pdf_sha1": "bebb5c6f63b3", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "413", "s": "0906", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00042', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-114-a7c7609b', 'sub-pukao-6f0ba476-02', NULL, 'single_choice', '關於動產質權消滅之事由，下列敘述，何者錯誤？', '["動產質權擔保之債權消滅", "質權人返還質物於出質人", "質權人喪失質物之占有，已於二年內請求返還", "質物滅失且出質人未受賠償或其他利益"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:43+00:00", "source_pdf_sha1": "b84e55ea72f9", "answer_pdf_sha1": "bebb5c6f63b3", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "413", "s": "0906", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00043', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-114-a7c7609b', 'sub-pukao-6f0ba476-02', NULL, 'single_choice', '甲搶奪乙之名畫，以所有之意思，十年間和平公然繼續占有之。乙不知甲之所在，並未對甲請求 返還。下列敘述，何者正確？', '["甲時效取得該名畫之所有權", "甲無法取得該名畫之所有權", "甲乙應共有該名畫之所有權", "乙仍然擁有該名畫之所有權"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:43+00:00", "source_pdf_sha1": "b84e55ea72f9", "answer_pdf_sha1": "bebb5c6f63b3", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "413", "s": "0906", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00044', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-114-a7c7609b', 'sub-pukao-6f0ba476-02', NULL, 'single_choice', '甲15歲，有手機1支。甲未得其法定代理人乙之同意，逕自拋棄該手機。該拋棄行為之效力為何？', '["效力未定", "得撤銷", "無效", "有效"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:43+00:00", "source_pdf_sha1": "b84e55ea72f9", "answer_pdf_sha1": "bebb5c6f63b3", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "413", "s": "0906", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00045', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-114-a7c7609b', 'sub-pukao-6f0ba476-02', NULL, 'single_choice', '下列何者屬於日常家務之範圍？', '["妻非處分其夫之不動產時，即不能維持家庭生活者", "妻為夫借貸買股票之目的，而設定普通抵押權之行為", "妻為夫向保險人申請終止保險契約，欲以解約金購買名牌包", "妻處分夫所有之汽車，而收藏古董"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:43+00:00", "source_pdf_sha1": "b84e55ea72f9", "answer_pdf_sha1": "bebb5c6f63b3", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "413", "s": "0906", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00046', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-114-a7c7609b', 'sub-pukao-6f0ba476-02', NULL, 'single_choice', '乙未婚生一子丙，其後，乙與甲結婚。下列關於準正之敘述，何者錯誤？', '["甲為丙之生父時，丙視為甲之婚生子女", "甲為丙之生父時，甲乙之婚姻無效者，丙不視為甲之婚生子女", "甲為丙之生父時，甲乙之婚姻被撤銷者，丙不視為甲之婚生子女", "甲非丙之生父時，甲丙間為直系姻親關係"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:43+00:00", "source_pdf_sha1": "b84e55ea72f9", "answer_pdf_sha1": "bebb5c6f63b3", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "413", "s": "0906", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00047', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-114-a7c7609b', 'sub-pukao-6f0ba476-02', NULL, 'single_choice', '甲已喪偶，有一成年之子乙，丙為甲之父，丁為甲之弟。甲不能維持生活又無謀生能力，乙、丙、 丁均有扶養能力。何人應優先扶養甲？', '["乙", "丙", "丁", "乙丁"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:43+00:00", "source_pdf_sha1": "b84e55ea72f9", "answer_pdf_sha1": "bebb5c6f63b3", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "413", "s": "0906", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00048', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-114-a7c7609b', 'sub-pukao-6f0ba476-02', NULL, 'single_choice', '下列關於法定之限定責任程序之敘述，何者正確？', '["法院於知悉被繼承人死亡時，得依職權命繼承人於六個月內提出遺產清冊", "繼承人於被繼承人死亡時起，應於六個月內開具遺產清冊陳報法院", "繼承人有數人時，其中一人已開具遺產清冊陳報法院者，其他繼承人仍須再為陳報，始為完備", "繼承人向法院陳報遺產清冊時，法院應依公示催告程序公告，命被繼承人之債權人於一定期限 內報明其債權"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:43+00:00", "source_pdf_sha1": "b84e55ea72f9", "answer_pdf_sha1": "bebb5c6f63b3", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "413", "s": "0906", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL)
